before_code:
module priority_encoder (
  input clk,
  input [15:0] req,
  output reg [3:0] grant
);
  always @(req[15] or req[14] or req[13]) begin
    if (req[15])
      grant = 4'hF;
    else if (req[14])
      grant = 4'hE;
    else if (req[13])
      grant = 4'hD;
    else if (req[12])
      grant = 4'hC;
    else
      grant = 4'h0;
  end
endmodule

after_code:
module priority_encoder (
  input clk,
  input [15:0] req,
  output reg [3:0] grant
);
  always @(*) begin
    if (req[15])
      grant = 4'hF;
    else if (req[14])
      grant = 4'hE;
    else if (req[13])
      grant = 4'hD;
    else if (req[12])
      grant = 4'hC;
    else
      grant = 4'h0;
  end
endmodule
